486	      { en: 'giraffe', cn: '长颈鹿', ph: '/dʒəˈrɑːf/' },
487	      { en: 'penguin', cn: '企鹅', ph: '/ˈpeŋɡwɪn/' },
488	      { en: 'butterfly', cn: '蝴蝶', ph: '/ˈbʌtəflaɪ/' },
489	      { en: 'rainbow', cn: '彩虹', ph: '/ˈreɪnbəʊ/' }
490	    ];
491	    let index = 0;
492	    let known = 3;
493	    let remaining = 7;
494	    const total = 10;
495	
496	    function updateCard() {
497	      const w = words[index % words.length];
498	      document.querySelector('[data-ui-id="study-word-front"]').textContent = w.en;
499	      document.querySelector('[data-ui-id="study-word-back-meaning"]').textContent = w.cn;
500	      document.querySelector('[data-ui-id="study-word-back-phonetic"]').textContent = w.ph;
501	      card.classList.remove('is-flipped');
502	    }
503	
504	    function updateProgress() {
505	      document.querySelector('[data-ui-id="study-remaining-count"]').textContent = remaining;
506	      document.querySelector('[data-ui-id="study-known-count"]').textContent = known;
507	      document.getElementById('progressFill').style.width = ((known / total) * 100) + '%';
508	    }
509	
510	    document.querySelector('[data-ui-id="study-known-button"]').addEventListener('click', () => {
511	      known = Math.min(total, known + 1);
512	      remaining = Math.max(0, remaining - 1);
513	      index++;
514	      updateProgress();
515	      updateCard();
516	    });
517	
518	    document.querySelector('[data-ui-id="study-unknown-button"]').addEventListener('click', () => {
519	      index++;
520	      updateCard();
521	    });
522	
523	    document.querySelector('[data-ui-id="study-restart-button"]').addEventListener('click', () => {
524	      document.getElementById('completionOverlay').classList.remove('is-visible');
525	      known = 0;
526	      remaining = total;
527	      index = 0;
528	      updateProgress();
529	      updateCard();
530	    });
531	
532	    // Demo: show completion overlay after 5 seconds for visual verification
533	    setTimeout(() => {
534	      document.getElementById('completionOverlay').classList.add('is-visible');
535	    }, 5000);
536	  </script>
537	</body>
