// FlashCard.ets
//
// 3D flip flashcard for the 童词卡 review surface.
//
// Visual contract: .arkpilot/designs/page-study.html (.flip-card). Front face
// shows the english word; back face shows the chinese meaning + phonetic.
//
// Flip mechanic: the parent owns isFlipped (StudySession). When it changes, the
// @Watch handler drives a single animateTo that rotates flipAngle 0 <-> 180
// (cubic-bezier overshoot matching the HTML transition). The two faces are
// stacked; the back is pre-rotated 180deg and each face's visibility is gated
// on the midpoint (90deg) so text never bleeds through during the flip.
//
// Semantic IDs (from ui-tree.json / design-alignment.md):
//   study-flashcard            -> root clickable card
//   study-word-front           -> english word text
//   study-word-back-meaning    -> chinese meaning text
//   study-word-back-phonetic   -> phonetic text

import { curves } from '@kit.ArkUI';
import { Theme } from '../common/Theme';
import { SvgIcon } from '../common/SvgIcon';

@Component
export struct FlashCard {
  @Prop english: string = '';
  @Prop meaning: string = '';
  @Prop phonetic: string = '';
  @Prop isFlipped: boolean = false;
  @State flipAngle: number = 0;
  onTap: () => void = () => {};

  @Watch('isFlipped')
  onFlipChanged(): void {
    animateTo({ duration: 800, curve: curves.cubicBezierCurve(0.34, 1.56, 0.64, 1) }, () => {
      this.flipAngle = this.isFlipped ? 180 : 0;
    });
  }

  build() {
    Stack() {
      // Front face: english word.
      Stack() {
        Column() {
          Row({ space: 6 }) {
            SvgIcon({ variant: 'flipHint', iconSize: 16 })
            Text('点我翻面')
              .fontSize(12)
              .fontWeight(FontWeight.Medium)
              .fontColor(Theme.primary)
          }
          .padding({ left: 14, right: 14, top: 8, bottom: 8 })
          .borderRadius(Theme.radiusPill)
          .backgroundColor('rgba(255,255,255,0.85)')
          .border({ width: 1, color: 'rgba(107,78,230,0.12)' }

          )

          Blank()

          Text(this.english)
            .id('study-word-front')
            .fontSize(54)
            .fontWeight(FontWeight.Bold)
            .fontColor(Theme.textPrimary)
            .textAlign(TextAlign.Center)
            .margin({ top: 8 })

          Blank()

          Text('点击卡片查看释义')
            .fontSize(13)
            .fontWeight(FontWeight.Medium)
            .fontColor(Theme.textTertiary)
        }
        .width('100%')
        .height('100%')
        .padding(32)
        .justifyContent(FlexAlign.SpaceBetween)
        .alignItems(HorizontalAlign.Center)
      }
      .width('100%')
      .height('100%')
      .backgroundColor(Theme.cardBg)
      .borderRadius(Theme.radiusCard)
      .border({ width: 1, color: Theme.borderSoft })
      .shadow({ radius: 60, color: 'rgba(107,78,230,0.18)', offsetX: 0, offsetY: 20 })
      .rotate({ y: this.flipAngle })
      .opacity(this.flipAngle <= 90 ? 1 : 0)

      // Back face: meaning + phonetic. Pre-rotated so it faces the user at 180.
      Stack() {
        Column() {
          Text('释义')
            .fontSize(12)
            .fontWeight(FontWeight.Bold)
            .fontColor(Theme.primary)
            .padding({ left: 16, right: 16, top: 8, bottom: 8 })
            .borderRadius(Theme.radiusPill)
            .backgroundColor('rgba(184,176,230,0.22)')
            .margin({ bottom: 28 })

          Text(this.phonetic)
            .id('study-word-back-phonetic')
            .fontSize(18)
            .fontWeight(FontWeight.Medium)
            .fontColor(Theme.textTertiary)
            .margin({ bottom: 18 })

          Divider()
            .width(60)
            .strokeWidth(1)
            .color(Theme.mist)
            .margin({ bottom: 22 })

          Text(this.meaning)
            .id('study-word-back-meaning')
            .fontSize(30)
            .fontWeight(FontWeight.Bold)
            .fontColor(Theme.textPrimary)
            .textAlign(TextAlign.Center)
        }
        .width('100%')
        .height('100%')
        .padding(32)
        .justifyContent(FlexAlign.Center)
        .alignItems(HorizontalAlign.Center)
      }
      .width('100%')
      .height('100%')
      .backgroundColor(Theme.cardBackBg)
      .borderRadius(Theme.radiusCard)
      .border({ width: 1, color: Theme.borderSoft })
      .shadow({ radius: 60, color: 'rgba(107,78,230,0.18)', offsetX: 0, offsetY: 20 })
      .rotate({ y: this.flipAngle - 180 })
      .opacity(this.flipAngle > 90 ? 1 : 0)
    }
    .width('100%')
    .height(460)
    .constraintSize({ maxWidth: 360 })
    .onClick(() => this.onTap())
    .id('study-flashcard')
  }
}

