// CompletionOverlay.ets
//
// Full-screen completion celebration shown when the review queue is empty.
//
// Visual contract: .arkpilot/designs/page-study.html (.completion-overlay).
// Decorative background stars carry no semantic IDs (purely decorative). The
// achievement star pops in with an overshoot scale animation on appear.
//
// Semantic IDs (from ui-tree.json / design-alignment.md):
//   study-completion-panel -> overlay root
//   study-empty-state      -> "已认识 X / Y 个单词" description
//   study-restart-button   -> 再复习一次 button

import { curves } from '@kit.ArkUI';
import { Theme } from '../common/Theme';
import { SvgIcon } from '../common/SvgIcon';

@Component
export struct CompletionOverlay {
  @Prop knownCount: number = 0;
  @Prop totalCount: number = 0;
  onRestart: () => void = () => {};
  @State badgeScale: number = 0;

  aboutToAppear(): void {
    animateTo({ duration: 600, curve: curves.cubicBezierCurve(0.34, 1.56, 0.64, 1) }, () => {
      this.badgeScale = 1;
    });
  }

  @Builder
  DecoStar(variant: string, size: number, posX: string, posY: string) {
    SvgIcon({ variant: variant, iconSize: size })
      .position({ x: posX, y: posY })
      .opacity(0.35)
  }

  build() {
    Stack() {
      // Decorative floating stars (no semantic IDs).
      this.DecoStar('decoStar1', 18, '12%', '10%')
      this.DecoStar('decoStar2', 14, '72%', '18%')
      this.DecoStar('decoStar3', 12, '8%', '42%')
      this.DecoStar('decoStar4', 20, '74%', '64%')
      this.DecoStar('decoStar5', 10, '16%', '80%')

      Column() {
        // Achievement star badge.
        Stack() {
          SvgIcon({ variant: 'star', iconSize: 64 })
        }
        .width(120)
        .height(120)
        .borderRadius(60)
        .linearGradient(Theme.starBadgeGradient())
        .shadow({ radius: 40, color: 'rgba(255,211,110,0.45)', offsetX: 0, offsetY: 16 })
        .scale({ x: this.badgeScale, y: this.badgeScale })
        .margin({ bottom: 28 })

        Text('太棒了！')
          .fontSize(40)
          .fontWeight(FontWeight.Bold)
          .fontColor(Theme.primary)
          .margin({ bottom: 10 })

        Text(`已认识 ${this.knownCount} / ${this.totalCount} 个单词`)
          .id('study-empty-state')
          .fontSize(16)
          .fontWeight(FontWeight.Medium)
          .fontColor(Theme.textSecondary)
          .margin({ bottom: 36 })

        Row({ space: 8 }) {
          SvgIcon({ variant: 'restart', iconSize: 20 })
          Text('再复习一次')
            .fontSize(17)
            .fontWeight(FontWeight.Bold)
            .fontColor('#FFFFFF')
        }
        .width('100%')
        .height(60)
        .borderRadius(Theme.radiusButton)
        .linearGradient(Theme.restartGradient())
        .shadow({ radius: 32, color: 'rgba(107,78,230,0.40)', offsetX: 0, offsetY: 12 })
        .justifyContent(FlexAlign.Center)
        .constraintSize({ maxWidth: 320 })
        .onClick(() => this.onRestart())
        .id('study-restart-button')
      }
      .width('100%')
      .constraintSize({ maxWidth: 320 })
      .justifyContent(FlexAlign.Center)
      .alignItems(HorizontalAlign.Center)
    }
    .width('100%')
    .height('100%')
    .radialGradient({
      center: [50, 20],
      radius: 120,
      colors: [['#F0E9FF', 0.0], ['#FAF8FF', 0.55], ['#FAF8FF', 1.0]],
    } as RadialGradientOptions)
    .id('study-completion-panel')
  }
}

