// StudyPage.ets
//
// The single review surface for 童词卡 (Kids Word Cards).
//
// Per spec sections 4/5 this is the app's only page: a frosted progress header,
// a centered 3D flip card, and a fixed bottom action bar with 认识 / 不认识.
// When the queue empties, the CompletionOverlay celebrates and offers a restart.
//
// State ownership: the StudySession view-model (@Observed) is owned by the
// @Entry shell (Index) and passed in via @ObjectLink so first-level property
// writes (queue reassignment, knownCount, isFlipped) rebuild this surface.
//
// Semantic IDs (from ui-tree.json / design-alignment.md):
//   study-progress-header, study-remaining-count, study-known-count,
//   study-known-button, study-unknown-button (bound here)
//   study-flashcard, study-word-front, study-word-back-meaning,
//   study-word-back-phonetic, study-completion-panel, study-empty-state,
//   study-restart-button (bound in child components)

import { Theme, BrandGradient } from '../common/Theme';
import { SvgIcon } from '../common/SvgIcon';
import { FlashCard } from '../components/FlashCard';
import { CompletionOverlay } from '../components/CompletionOverlay';
import { StudySession } from '../viewmodel/StudySession';
import { WordItem } from '../model/WordItem';

@Component
export struct StudyPage {
  @ObjectLink session: StudySession;

  private progressPercent(): number {
    if (this.session.totalCount <= 0) {
      return 0;
    }
    return Math.round((this.session.knownCount / this.session.totalCount) * 100);
  }

  @Builder
  Header() {
    Column() {
      Row() {
        Row({ space: 10 }) {
          SvgIcon({ variant: 'brand', iconSize: 26 })
          Text('今日复习')
            .fontSize(22)
            .fontWeight(FontWeight.Bold)
            .fontColor(Theme.primary)
        }

        Row({ space: 20 }) {
          Column() {
            Text(`${this.session.remainingCount}`)
              .id('study-remaining-count')
              .fontSize(20)
              .fontWeight(FontWeight.Bold)
              .fontColor(Theme.textPrimary)
            Text('剩余')
              .fontSize(11)
              .fontWeight(FontWeight.Medium)
              .fontColor(Theme.textTertiary)
              .margin({ top: 2 })
          }
          Column() {
            Text(`${this.session.knownCount}`)
              .id('study-known-count')
              .fontSize(20)
              .fontWeight(FontWeight.Bold)
              .fontColor(Theme.textPrimary)
            Text('已认识')
              .fontSize(11)
              .fontWeight(FontWeight.Medium)
              .fontColor(Theme.textTertiary)
              .margin({ top: 2 })
          }
        }
      }
      .width('100%')
      .justifyContent(FlexAlign.SpaceBetween)
      .alignItems(VerticalAlign.Center)
      .margin({ bottom: 16 })

      // Progress track + animated fill.
      Stack({ alignContent: Alignment.Start }) {
        Row()
          .width(`${this.progressPercent()}%`)
          .height(10)
          .borderRadius(5)
          .linearGradient(BrandGradient.progress)
          .animation({ duration: 350, curve: Curve.EaseOut })
      }
      .width('100%')
      .height(10)
      .borderRadius(5)
      .backgroundColor(Theme.progressTrack())
    }
    .width('100%')
    .padding({ top: 56, bottom: 16, left: Theme.pageHorizontalPadding, right: Theme.pageHorizontalPadding })
    .backgroundColor(Theme.glassBg)
    .backgroundBlurStyle(BlurStyle.COMPONENT_THICK)
    .borderRadius({ bottomLeft: Theme.radiusHero, bottomRight: Theme.radiusHero })
    .id('study-progress-header')
  }

  @Builder
  CardStage() {
    Column() {
      if (this.session.currentWord !== undefined) {
        FlashCard({
          english: (this.session.currentWord as WordItem).english,
          meaning: (this.session.currentWord as WordItem).meaning,
          phonetic: (this.session.currentWord as WordItem).phonetic,
          isFlipped: this.session.isFlipped,
          onTap: () => this.session.toggleFlip(),
        })
      } else if (this.session.isEmpty) {
        Text('暂无可复习的单词')
          .fontSize(16)
          .fontColor(Theme.textSecondary)
      }
    }
    .width('100%')
    .height('100%')
    .padding({ left: Theme.pageHorizontalPadding, right: Theme.pageHorizontalPadding })
    .justifyContent(FlexAlign.Center)
    .alignItems(HorizontalAlign.Center)
  }

  @Builder
  ActionBar() {
    Column() {
      Row({ space: 14 }) {
        Row({ space: 8 }) {
          SvgIcon({ variant: 'unknown', iconSize: 20 })
          Text('不认识')
            .fontSize(17)
            .fontWeight(FontWeight.Bold)
            .fontColor('#FFFFFF')
        }
        .layoutWeight(1)
        .height(60)
        .borderRadius(Theme.radiusButton)
        .linearGradient(BrandGradient.unknownBtn)
        .shadow({ radius: 32, color: 'rgba(255,140,105,0.40)', offsetX: 0, offsetY: 12 })
        .justifyContent(FlexAlign.Center)
        .onClick(() => this.session.markUnknown())
        .id('study-unknown-button')

        Row({ space: 8 }) {
          SvgIcon({ variant: 'known', iconSize: 20 })
          Text('认识')
            .fontSize(17)
            .fontWeight(FontWeight.Bold)
            .fontColor('#FFFFFF')
        }
        .layoutWeight(1)
        .height(60)
        .borderRadius(Theme.radiusButton)
        .linearGradient(BrandGradient.knownBtn)
        .shadow({ radius: 32, color: 'rgba(61,217,160,0.45)', offsetX: 0, offsetY: 12 })
        .justifyContent(FlexAlign.Center)
        .onClick(() => this.session.markKnown())
        .id('study-known-button')
      }
      .width('100%')
    }
    .width('100%')
    .padding({ top: 20, bottom: 20, left: Theme.pageHorizontalPadding, right: Theme.pageHorizontalPadding })
    .backgroundColor(Theme.glassBg)
    .backgroundBlurStyle(BlurStyle.COMPONENT_THICK)
    .borderRadius({ topLeft: Theme.radiusHero, topRight: Theme.radiusHero })
    .shadow({ radius: 24, color: 'rgba(107,78,230,0.08)', offsetX: 0, offsetY: -4 })
  }

  build() {
    Stack() {
      Column() {
        this.Header()
        this.CardStage()
        this.ActionBar()
      }
      .width('100%')
      .height('100%')
      .constraintSize({ maxWidth: Theme.contentMaxWidth })
      .backgroundColor(Theme.pageBg)

      if (this.session.isComplete) {
        CompletionOverlay({
          knownCount: this.session.knownCount,
          totalCount: this.session.totalCount,
          onRestart: () => this.session.restart(),
        })
      }
    }
    .width('100%')
    .height('100%')
    .backgroundColor(Theme.pageBg)
  }
}

