import { curves } from '@kit.ArkUI';
import { Theme, BrandGradient } from '../common/Theme';
import { StudySession } from '../viewmodel/StudySession';
import { WordItem } from '../model/WordItem';
import { SvgIcon } from '../common/SvgIcon';

@Component
export struct StudyPage {
  // Logic owner. Not @State: we mirror the fields the UI binds to into @State
  // below and refresh them through syncState() after every action, so the build
  // only ever reads reactive @State values.
  private session: StudySession = new StudySession();

  @State remainingCount: number = 0;
  @State knownCount: number = 0;
  @State totalCount: number = 0;
  @State currentWord: WordItem | undefined = undefined;
  @State isComplete: boolean = false;
  @State cardRotation: number = 0;
  @State slideOffsetX: number = 0;
  @State slideOpacity: number = 1;

  private readonly cardWidth: number = 360;
  private readonly cardHeight: number = 460;

  aboutToAppear(): void {
    this.syncState();
  }

  private syncState(): void {
    this.remainingCount = this.session.remainingCount;
    this.knownCount = this.session.knownCount;
    this.totalCount = this.session.totalCount;
    this.currentWord = this.session.currentWord;
    this.isComplete = this.session.isComplete;
  }

  build() {
    Stack({ alignContent: Alignment.Top }) {
      Column() {
        this.Header()
        this.CardStage()
      }
      .width('100%')
      .height('100%')
      .padding({
        left: Theme.pageHorizontalPadding,
        right: Theme.pageHorizontalPadding,
        bottom: 112
      })

      this.ActionBar()

      if (this.isComplete) {
        this.CompletionOverlay()
      }
    }
    .width('100%')
    .height('100%')
    .backgroundColor(Theme.pageBg)
  }

  @Builder
  Header() {
    Column() {
      Row() {
        Row({ space: 10 }) {
          SvgIcon({ variant: 'brand', iconSize: 26 })
          Text('今日复习')
            .fontSize(22)
            .fontWeight(FontWeight.Bold)
            .fontColor(Theme.brandPrimary)
            .letterSpacing(-0.2)
        }

        Row({ space: 20 }) {
          this.StatColumn('剩余', this.remainingCount, 'study-remaining-count')
          this.StatColumn('已认识', this.knownCount, 'study-known-count')
        }
      }
      .width('100%')
      .justifyContent(FlexAlign.SpaceBetween)
      .alignItems(VerticalAlign.Center)

      Stack() {
        Row()
          .width('100%')
          .height(10)
          .borderRadius(5)
          .backgroundColor(Theme.borderDefault)

        Row()
          .width(this.totalCount === 0 ? '0%' : `${(this.knownCount / this.totalCount) * 100}%`)
          .height(10)
          .borderRadius(5)
          .linearGradient(BrandGradient.progress)
          .animation({ duration: 350, curve: Curve.EaseOut })
      }
      .width('100%')
      .margin({ top: 16 })
    }
    .id('study-progress-header')
    .width('100%')
    .padding({ top: 56, bottom: 16 })
    .backgroundColor(Theme.glassBg)
    .backdropBlur(20)
    .borderRadius({ bottomLeft: 24, bottomRight: 24 })
  }

  @Builder
  StatColumn(label: string, value: number, idValue: string) {
    Column() {
      Text(`${value}`)
        .id(idValue)
        .fontSize(20)
        .fontWeight(FontWeight.Bold)
        .fontColor(Theme.textPrimary)
        .letterSpacing(-0.3)

      Text(label)
        .fontSize(11)
        .fontWeight(FontWeight.Medium)
        .fontColor(Theme.textTertiary)
        .letterSpacing(0.4)
        .margin({ top: 2 })
    }
    .alignItems(HorizontalAlign.End)
  }

  @Builder
  CardStage() {
    Column() {
      if (this.currentWord !== undefined) {
        Stack() {
          // Front face: english word.
          Column() {
            this.CardBadge('flipHint', '点我翻面')
            Text(this.currentWord.english)
              .id('study-word-front')
              .fontSize(54)
              .fontWeight(FontWeight.Bold)
              .fontColor(Theme.textPrimary)
              .letterSpacing(-0.6)
              .lineHeight(54)
              .textAlign(TextAlign.Center)

            Text('点击卡片查看释义')
              .fontSize(13)
              .fontWeight(FontWeight.Medium)
              .fontColor(Theme.textTertiary)
              .position({ y: 180 })
          }
          .width('100%')
          .height('100%')
          .justifyContent(FlexAlign.Center)
          .alignItems(HorizontalAlign.Center)
          .backgroundColor(Theme.cardBg)
          .borderRadius(Theme.radiusCard)
          .border({ width: 1, color: Theme.borderSoft })
          .shadow({ radius: 60, color: 'rgba(107,78,230,0.18)', offsetX: 0, offsetY: 20 })
          // 3D flip around the Y axis; visibility gated at the 90deg midpoint.
          .rotate({ y: this.cardRotation })
          .opacity(this.cardRotation <= 90 ? 1 : 0)

          // Back face: meaning + phonetic, pre-rotated to face the user at 180.
          Column() {
            Text('释义')
              .fontSize(12)
              .fontWeight(FontWeight.Bold)
              .fontColor(Theme.brandPrimary)
              .letterSpacing(0.5)
              .padding({ left: 16, right: 16, top: 8, bottom: 8 })
              .backgroundColor('rgba(184,176,230,0.22)')
              .borderRadius(Theme.radiusPill)
              .margin({ bottom: 28 })

            Text(this.currentWord.phonetic)
              .id('study-word-back-phonetic')
              .fontSize(18)
              .fontWeight(FontWeight.Medium)
              .fontColor(Theme.textTertiary)
              .letterSpacing(0.2)
              .lineHeight(27)

            Row()
              .width(60)
              .height(1)
              .border({ width: { top: 1 }, color: Theme.cardDivider, style: { top: BorderStyle.Dashed } })
              .margin({ top: 18, bottom: 22 })

            Text(this.currentWord.meaning)
              .id('study-word-back-meaning')
              .fontSize(30)
              .fontWeight(FontWeight.Bold)
              .fontColor(Theme.textPrimary)
              .lineHeight(40.5)
              .textAlign(TextAlign.Center)
          }
          .width('100%')
          .height('100%')
          .justifyContent(FlexAlign.Center)
          .alignItems(HorizontalAlign.Center)
          .backgroundColor(Theme.cardBackBg)
          .borderRadius(Theme.radiusCard)
          .border({ width: 1, color: Theme.borderSoft })
          .shadow({ radius: 60, color: 'rgba(107,78,230,0.18)', offsetX: 0, offsetY: 20 })
          .rotate({ y: this.cardRotation - 180 })
          .opacity(this.cardRotation > 90 ? 1 : 0)
        }
        .id('study-flashcard')
        .width('100%')
        .constraintSize({ maxWidth: this.cardWidth })
        .height(this.cardHeight)
        .margin({ top: 48 })
        .onClick(() => this.onFlip())
        .translate({ x: this.slideOffsetX })
        .opacity(this.slideOpacity)
        .animation({ duration: 350, curve: Curve.EaseOut })
      } else {
        this.EmptyState()
      }
    }
    .width('100%')
    .height('100%')
    .alignItems(HorizontalAlign.Center)
  }

  @Builder
  CardBadge(iconVariant: string, label: string) {
    Row({ space: 6 }) {
      SvgIcon({ variant: iconVariant, iconSize: 16 })
      Text(label)
        .fontSize(12)
        .fontWeight(FontWeight.Bold)
        .fontColor(Theme.brandPrimary)
    }
    .padding({ left: 14, right: 14, top: 8, bottom: 8 })
    .backgroundColor('rgba(255,255,255,0.85)')
    .borderRadius(Theme.radiusPill)
    .border({ width: 1, color: Theme.borderSoft })
    .position({ y: -160 })
  }

  @Builder
  EmptyState() {
    Column() {
      Text('还没有单词哦')
        .fontSize(22)
        .fontWeight(FontWeight.Bold)
        .fontColor(Theme.textPrimary)
        .margin({ bottom: 8 })

      Text('当前阶段词库为空，请联系家长添加单词。')
        .fontSize(14)
        .fontColor(Theme.textSecondary)
        .textAlign(TextAlign.Center)
    }
    .width('100%')
    .height(this.cardHeight)
    .justifyContent(FlexAlign.Center)
    .alignItems(HorizontalAlign.Center)
    .margin({ top: 48 })
  }

  @Builder
  ActionBar() {
    Row({ space: 14 }) {
      this.ActionButton(
        '不认识',
        'unknown',
        'study-unknown-button',
        BrandGradient.unknownBtn,
        Theme.accentOrange,
        () => this.onMarkUnknown()
      )
      this.ActionButton(
        '认识',
        'known',
        'study-known-button',
        BrandGradient.knownBtn,
        Theme.accentGreen,
        () => this.onMarkKnown()
      )
    }
    .width('100%')
    .padding({ left: Theme.pageHorizontalPadding, right: Theme.pageHorizontalPadding, top: 20, bottom: 28 })
    .backgroundColor(Theme.glassBg)
    .backdropBlur(20)
    .borderRadius({ topLeft: 24, topRight: 24 })
    .position({ y: '100%' })
    .translate({ y: -108 })
  }

  @Builder
  ActionButton(label: string, iconVariant: string, idValue: string, gradient: LinearGradient,
    shadowColor: string, onClick: () => void) {
    Button() {
      Row({ space: 8 }) {
        SvgIcon({ variant: iconVariant, iconSize: 20 })
        Text(label)
          .fontSize(17)
          .fontWeight(FontWeight.Bold)
          .fontColor('#FFFFFF')
      }
    }
    .id(idValue)
    .type(ButtonType.Normal)
    .borderRadius(Theme.radiusButton)
    .backgroundColor(Color.Transparent)
    .linearGradient(gradient)
    .height(60)
    .layoutWeight(1)
    .shadow({ radius: 32, color: `${shadowColor}73`, offsetX: 0, offsetY: 12 })
    .onClick(onClick)
  }

  @Builder
  CompletionOverlay() {
    Stack() {
      // Decorative floating stars (no semantic IDs).
      SvgIcon({ variant: 'decoStar1', iconSize: 18 })
        .position({ x: '12%', y: '10%' })
        .opacity(0.35)
