          .rotate({ y: this.cardRotation })
          .opacity(this.cardRotation <= 90 ? 1 : 0)

          // Back face: meaning + phonetic, pre-rotated to face the user at 180.
          Column() {
            Text('释义')
              .fontSize(12)
              .fontWeight(FontWeight.Bold)
              .fontColor(Theme.brandPrimary)
              .letterSpacing(0.5)
              .padding({ left: 16, right: 16, top: 8, bottom: 8 })
              .backgroundColor('rgba(184,176,230,0.22)')
              .borderRadius(Theme.radiusPill)
              .margin({ bottom: 28 })

            Text(this.currentWord.phonetic)
              .id('study-word-back-phonetic')
              .fontSize(18)
              .fontWeight(FontWeight.Medium)
              .fontColor(Theme.textTertiary)
              .letterSpacing(0.2)
              .lineHeight(27)

            Row()
              .width(60)
              .height(1)
              .border({ width: { top: 1 }, color: Theme.cardDivider, style: { top: BorderStyle.Dashed } })
              .margin({ top: 18, bottom: 22 })

            Text(this.currentWord.meaning)
              .id('study-word-back-meaning')
              .fontSize(30)
              .fontWeight(FontWeight.Bold)
              .fontColor(Theme.textPrimary)
              .lineHeight(40.5)
              .textAlign(TextAlign.Center)
          }
          .width('100%')
          .height('100%')
          .justifyContent(FlexAlign.Center)
          .alignItems(HorizontalAlign.Center)
          .backgroundColor(Theme.cardBackBg)
          .borderRadius(Theme.radiusCard)
          .border({ width: 1, color: Theme.borderSoft })
          .shadow({ radius: 60, color: 'rgba(107,78,230,0.18)', offsetX: 0, offsetY: 20 })
          .rotate({ y: this.cardRotation - 180 })
          .opacity(this.cardRotation > 90 ? 1 : 0)
        }
        .id('study-flashcard')
        .width('100%')
        .constraintSize({ maxWidth: this.cardWidth })
        .height(this.cardHeight)
        .margin({ top: 48 })
        .onClick(() => this.onFlip())
        .translate({ x: this.slideOffsetX })
        .opacity(this.slideOpacity)
        .animation({ duration: 350, curve: Curve.EaseOut })
      } else {
        this.EmptyState()
      }
    }
    .width('100%')
    .height('100%')
    .alignItems(HorizontalAlign.Center)
  }

  @Builder
  CardBadge(iconVariant: string, label: string) {
    Row({ space: 6 }) {
      SvgIcon({ variant: iconVariant, iconSize: 16 })
      Text(label)
        .fontSize(12)
        .fontWeight(FontWeight.Bold)
        .fontColor(Theme.brandPrimary)
    }
    .padding({ left: 14, right: 14, top: 8, bottom: 8 })
    .backgroundColor('rgba(255,255,255,0.85)')
    .borderRadius(Theme.radiusPill)
    .border({ width: 1, color: Theme.borderSoft })
    .position({ y: -160 })
  }

  @Builder
  EmptyState() {
    Column() {
      Text('还没有单词哦')
        .fontSize(22)
        .fontWeight(FontWeight.Bold)
        .fontColor(Theme.textPrimary)
        .margin({ bottom: 8 })

      Text('当前阶段词库为空，请联系家长添加单词。')
        .fontSize(14)
        .fontColor(Theme.textSecondary)
        .textAlign(TextAlign.Center)
    }
    .width('100%')
    .height(this.cardHeight)
    .justifyContent(FlexAlign.Center)
    .alignItems(HorizontalAlign.Center)
    .margin({ top: 48 })
  }

  @Builder
  ActionBar() {
    Row({ space: 14 }) {
      this.ActionButton(
        '不认识',
        'unknown',
        'study-unknown-button',
        BrandGradient.unknownBtn,
        Theme.accentOrange,
        () => this.onMarkUnknown()
      )
      this.ActionButton(
        '认识',
        'known',
        'study-known-button',
        BrandGradient.knownBtn,
        Theme.accentGreen,
        () => this.onMarkKnown()
      )
    }
    .width('100%')
    .padding({ left: Theme.pageHorizontalPadding, right: Theme.pageHorizontalPadding, top: 20, bottom: 28 })
    .backgroundColor(Theme.glassBg)
    .backdropBlur(20)
    .borderRadius({ topLeft: 24, topRight: 24 })
    .position({ y: '100%' })
    .translate({ y: -108 })
  }

  @Builder
  ActionButton(label: string, iconVariant: string, idValue: string, gradient: LinearGradient,
    shadowColor: string, onClick: () => void) {
    Button() {
      Row({ space: 8 }) {
        SvgIcon({ variant: iconVariant, iconSize: 20 })
        Text(label)
          .fontSize(17)
          .fontWeight(FontWeight.Bold)
          .fontColor('#FFFFFF')
      }
    }
    .id(idValue)
    .type(ButtonType.Normal)
    .borderRadius(Theme.radiusButton)
    .backgroundColor(Color.Transparent)
    .linearGradient(gradient)
    .height(60)
    .layoutWeight(1)
    .shadow({ radius: 32, color: `${shadowColor}73`, offsetX: 0, offsetY: 12 })
    .onClick(onClick)
  }

  @Builder
  CompletionOverlay() {
    Stack() {
      // Decorative floating stars (no semantic IDs).
      SvgIcon({ variant: 'decoStar1', iconSize: 18 })
        .position({ x: '12%', y: '10%' })
        .opacity(0.35)
      SvgIcon({ variant: 'decoStar2', iconSize: 14 })
        .position({ x: '78%', y: '16%' })
        .opacity(0.35)
      SvgIcon({ variant: 'decoStar3', iconSize: 12 })
        .position({ x: '10%', y: '40%' })
        .opacity(0.35)
      SvgIcon({ variant: 'decoStar4', iconSize: 20 })
        .position({ x: '82%', y: '72%' })
        .opacity(0.35)
      SvgIcon({ variant: 'decoStar5', iconSize: 10 })
        .position({ x: '18%', y: '84%' })
        .opacity(0.35)

      Column() {
        Stack() {
          Column()
            .width(120)
            .height(120)
            .borderRadius(60)
            .linearGradient({
              angle: 135,
              direction: GradientDirection.RightTop,
              colors: [[Theme.goldStart, 0.0], [Theme.gold, 1.0]]
            })
            .shadow({ radius: 40, color: 'rgba(255,211,110,0.45)', offsetX: 0, offsetY: 16 })

          SvgIcon({ variant: 'star', iconSize: 64 })
        }
        .margin({ bottom: 28 })

        Text('太棒了！')
          .fontSize(40)
          .fontWeight(FontWeight.Bold)
          .fontColor(Theme.brandPrimary)
          .letterSpacing(-0.4)
          .lineHeight(44)
          .margin({ bottom: 10 })

        Text(`已认识 ${this.knownCount} / ${this.totalCount} 个单词`)
          .id('study-empty-state')
          .fontSize(16)
          .fontWeight(FontWeight.Medium)
          .fontColor(Theme.textSecondary)
          .margin({ bottom: 36 })

        Button() {
          Row({ space: 8 }) {
            SvgIcon({ variant: 'restart', iconSize: 20 })
            Text('再复习一次')
              .fontSize(17)
              .fontWeight(FontWeight.Bold)
              .fontColor('#FFFFFF')
          }
        }
        .id('study-restart-button')
        .type(ButtonType.Normal)
        .borderRadius(Theme.radiusButton)
        .backgroundColor(Color.Transparent)
        .linearGradient(BrandGradient.primary)
        .width('100%')
        .constraintSize({ maxWidth: 320 })
        .height(60)
        .shadow({ radius: 32, color: 'rgba(107,78,230,0.40)', offsetX: 0, offsetY: 12 })
        .onClick(() => this.onRestart())
      }
      .width('100%')
      .height('100%')
      .justifyContent(FlexAlign.Center)
      .alignItems(HorizontalAlign.Center)
      .padding({ left: 24, right: 24 })
    }
    .id('study-completion-panel')
    .width('100%')
    .height('100%')
    .backgroundColor(Color.Transparent)
    .linearGradient({
      angle: 180,
      direction: GradientDirection.Bottom,
      colors: [['#F0E9FF', 0.0], ['#FAF8FF', 0.55], ['#FAF8FF', 1.0]]
    })
  }

  // toggle-flip-card: 3D Y-axis flip driven by animateTo (800ms overshoot).
  private onFlip(): void {
    this.session.toggleFlip();
    const target: number = this.session.isFlipped ? 180 : 0;
    animateTo({ duration: 800, curve: curves.cubicBezierCurve(0.34, 1.56, 0.64, 1) }, () => {
      this.cardRotation = target;
    });
  }

  private onMarkKnown(): void {
    if (this.currentWord === undefined) {
      return;
    }
    this.animateCardOut(1, () => {
      this.session.markKnown();
      this.syncState();
      this.resetCardAnimation();
    });
  }

  private onMarkUnknown(): void {
    if (this.currentWord === undefined) {
      return;
    }
    this.animateCardOut(-1, () => {
      this.session.markUnknown();
      this.syncState();
      this.resetCardAnimation();
    });
  }

  private onRestart(): void {
    this.session.restart();
    this.cardRotation = 0;
    this.syncState();
  }

  private animateCardOut(direction: number, onDone: () => void): void {
    this.slideOffsetX = direction * 400;
    this.slideOpacity = 0;
    setTimeout(onDone, 360);
  }

  private resetCardAnimation(): void {
    this.slideOffsetX = 0;
    this.slideOpacity = 1;
    this.cardRotation = 0;
  }
}

