// Index.ets
//
// App shell / entry page for 童词卡 (Kids Word Cards).
//
// Spec sections 4/5 require a single-page app with NO bottom tab navigation:
// launch directly into the review surface. This shell simply hosts StudyPage,
// constrained to the design content width and centered on wide screens.
//
// The scaffold's BottomTabBar/TabTypes shell is intentionally unused (kept on
// disk for a possible future tab extension); see the change request recorded in
// .arkpilot/designs/ui-behavior.json.

import { Theme } from '../common/Theme';
import { StudyPage } from './StudyPage';

@Entry
@Component
struct Index {
  build() {
    Column() {
      StudyPage()
    }
    .width('100%')
    .height('100%')
    .constraintSize({ maxWidth: Theme.contentMaxWidth })
    .backgroundColor(Theme.pageBg)
  }
}

